Use ASP.NET Core's **`WebApplicationFactory<T>`** — it creates an in-memory `TestServer` and gives you an `HttpClient` that speaks to it over HTTP without opening a real port.

### Setup

```bash
dotnet add tests/MyMcp.Tests package Microsoft.AspNetCore.Mvc.Testing
dotnet add tests/MyMcp.Tests package xunit
```

### Example test

```csharp
public class McpIntegrationTests
    : IClassFixture<WebApplicationFactory<Program>>
{
    private readonly HttpClient _client;

    public McpIntegrationTests(WebApplicationFactory<Program> factory)
    {
        _client = factory.CreateClient();
    }

    [Fact]
    public async Task Initialize_ReturnsServerCapabilities()
    {
        var request = new
        {
            jsonrpc = "2.0",
            id = 1,
            method = "initialize",
            @params = new
            {
                protocolVersion = "2025-03-26",
                capabilities = new { },
                clientInfo = new { name = "test-client", version = "1.0" }
            }
        };

        var response = await _client.PostAsJsonAsync("/mcp", request);

        response.EnsureSuccessStatusCode();
        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        Assert.Equal("2.0", body.GetProperty("jsonrpc").GetString());
        Assert.Equal(1, body.GetProperty("id").GetInt32());
        Assert.True(body.GetProperty("result")
                        .TryGetProperty("capabilities", out _));
    }

    [Fact]
    public async Task ToolsCall_InvokesTool()
    {
        // initialize first (required by MCP)
        await InitializeAsync();

        var request = new
        {
            jsonrpc = "2.0",
            id = 2,
            method = "tools/call",
            @params = new
            {
                name = "my-tool",
                arguments = new { input = "hello" }
            }
        };

        var response = await _client.PostAsJsonAsync("/mcp", request);

        response.EnsureSuccessStatusCode();
        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        var content = body.GetProperty("result")
                         .GetProperty("content")[0];
        Assert.Equal("text", content.GetProperty("type").GetString());
    }

    private async Task InitializeAsync() { /* send initialize + initialized */ }
}
```

### Key points

| Concern | Approach |
|---|---|
| **No real port** | `WebApplicationFactory` uses an in-memory `TestServer` |
| **Override services** | Call `factory.WithWebHostBuilder(b => b.ConfigureServices(...))` to swap in mocks/fakes |
| **SSE transport** | Use `factory.CreateDefaultClient()` and read the SSE stream with `HttpCompletionOption.ResponseHeadersRead` |
| **Streamable HTTP** | POST JSON-RPC to your MCP endpoint; assert on the JSON-RPC response |
| **Stateful sessions** | Send `initialize` → `initialized` before each test, or do it once in a fixture |

This gives you full HTTP fidelity (middleware, routing, content negotiation) with in-process speed.
